var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"우웅, 그런데 여기서는 뭐라고 불러야 할지 잘 모르겠네요?","JPN":"うーん、ところでここではなんと呼べばいいのかわかりませんね？","ENG":"Mmh, I'm not sure how to refer to you here.","TWN":"嗯～真不知道該怎麼稱呼你才好呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"어머니께서는 어떤 호칭으로 부르셨는지 모르겠지만, 저희는 오라버니를 각자 다르게 생각하거든요.","JPN":"お母さんはどのような呼称でお呼びだったのかわかりませんが、我々はお兄様のことにみんな違う感想を抱いているのです。","ENG":"I don't know what Mother used to call you, but we all have different names for you.","TWN":"雖然不知道母親是怎麼稱呼哥哥的，但我們每個人對哥哥的看法都不一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"어떤 호칭으로 불러드릴까요? 사장님? 오래된 목소리? 현자? 관리자님……?","JPN":"どのような呼称でお呼びしましょうか？　社長？　古い声？　賢者？　管理者様……？","ENG":"What do you want to be called? Boss? Old Voice? Sage? Administrator...?","TWN":"該用什麼稱呼好呢？老闆？老聲音？賢者？管理者……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"하핫! 그럼, 이브는 오라버니를 오라버니라고 부를래요!","JPN":"あはっ！　それでは、私はお兄様のことをお兄様と呼びますね！","ENG":"Haha! Then, Eve is going to call you Mister!","TWN":"哈哈！那麼，伊芙就叫你哥哥吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"그러니까 오라버니도 이브를 이브라고 불러주세요!","JPN":"ですから、お兄様も私のことをイヴとお呼びください！","ENG":"So you should call Eve Eve!","TWN":"所以哥哥也叫伊芙的名字吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"저는 오라버니 같은 인간이 좋아요. 오라버니한테서는 감미로운 냄새가 나거든요.","JPN":"私はお兄様のような人間が好きです。お兄様からは甘美な香りがするのです。","ENG":"I like humans like you, Mister. I smell something sweet from you.","TWN":"我喜歡像哥哥這種人，你身上有一股甜美的味道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"아픔도, 고통도, 슬픔도, 분노도, 사랑도, 즐거움도…….","JPN":"痛みも、苦痛も、悲しみも、怒りも、愛も、楽しさも……","ENG":"Pain, suffering, sorrow, anger, love, joy...","TWN":"痛苦、折磨、悲傷、憤怒、愛、喜悅……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"평범한 인간은 견딜 수조차 없을 정도로 가슴 속…… 여기에 많은 정보를 담고 계시잖아요?","JPN":"普通の人間は耐えられないほどに、胸の中……ここに多くの情報を持っているではないですか。","ENG":"You have so much information right... here. Which an ordinary human even can't bear them.","TWN":"你這裡有很多連平凡的人類無法承受的……資訊對嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"앗! 판! 나와버리면 어떡해?","JPN":"あっ！　パン！　出たら駄目よ。","ENG":"Oh! Pan! You can't just come out like that!","TWN":"哎呀！潘！你不可以出來啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"옳지, 옳지~ 엄마 중요한 얘기하고 있으니까 배가 고파도 조금만 참자?","JPN":"よし、よし～お母さんは大事な話をしてるんだから、お腹空いてもちょっとだけ我慢しようね。","ENG":"There, there. Mommy's having an important conversation, so be more patient.","TWN":"你乖～媽媽在談很重要的事，肚子餓也先忍忍。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"휴, 하마터면 오라버니 잡아먹을 뻔했다.","JPN":"ふう、お兄様を食べちゃうことろだった。","ENG":"Phew. It almost ate you, Mister.","TWN":"呼，差點就把哥哥吃掉咧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"우후후, 걱정마세요.","JPN":"うふふ、心配しないでください。","ENG":"Fu fuu fuu. Don't worry.","TWN":"呵呵呵，別擔心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"이브는 가장 맛있어 보이는 건 마지막까지 남겨두는 편이거든요.","JPN":"私は一番おいしそうなものを最後まで残しておく方なんです。","ENG":"Eve saves the best for last.","TWN":"別擔心，伊芙喜歡把最好吃的留到最後。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"오라버니는 저희에게 있어서 무척 중요한 존재니까 아무리 배가 고파도 참을 수 있다구요!","JPN":"お兄様は我々にとってとても重要な存在ですから、いくらお腹が空いても我慢できます！","ENG":"You're really important to us, so we can be patient, even if we're super hungry!","TWN":"畢竟哥哥對我們來說非常重要，所以再怎麼餓我也能忍耐的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"그러니까 이 계약서에는 미리 사인해둘게요.","JPN":"だから、この契約書にはサインしておきますね。","ENG":"So, I'll sign this contract now.","TWN":"所以這份合約我會先簽好。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"앞으로도 오래오래…… 오라버니를 보고 싶으니까요. 우후후.","JPN":"これからもずっと……お兄様に会いたいですから。うふふ。","ENG":"Because we'll see you... for a long time. Fu fuu fuu.","TWN":"因為我以後也想要一直一直……見到哥哥，呵呵呵。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};